import React, { useEffect, useState } from 'react';
import axios from 'axios';
import { usePlayer } from '../context/PlayerContext';
import { FaPlay, FaHeart } from 'react-icons/fa';

const Home = () => {
  const [songs, setSongs] = useState([]);
  const { playSong } = usePlayer();

  // Fetch songs từ Backend
  useEffect(() => {
    const fetchSongs = async () => {
      try {
        const res = await axios.get('http://localhost:5000/api/songs');
        setSongs(res.data);
      } catch (err) {
        console.error("Error fetching songs:", err);
      }
    };
    fetchSongs();
  }, []);

  // Xử lý Play + Tăng view
  const handlePlay = async (song) => {
      playSong(song);
      try {
          await axios.put(`http://localhost:5000/api/songs/${song._id}/play`);
      } catch (err) {
          console.error(err);
      }
  };

  // Xử lý Like
  const handleLike = async (id) => {
      try {
          const res = await axios.put(`http://localhost:5000/api/songs/${id}/like`);
          // Cập nhật UI ngay lập tức
          setSongs(songs.map(song => song._id === id ? { ...song, likes: res.data.likes } : song));
      } catch (err) {
          console.error(err);
      }
  };

  return (
    <div className="p-8 pb-24 bg-gray-100 min-h-screen">
      <h2 className="text-2xl font-bold mb-6 text-gray-800">Trending Now</h2>
      
      <div className="grid grid-cols-2 md:grid-cols-4 lg:grid-cols-5 gap-6">
        {songs.map((song) => (
          <div key={song._id} className="bg-white p-4 rounded-lg shadow hover:shadow-lg transition group">
            <div className="relative overflow-hidden rounded-md mb-3">
              <img src={song.coverImage} alt={song.title} className="w-full aspect-square object-cover" />
              <div className="absolute inset-0 bg-black bg-opacity-0 group-hover:bg-opacity-40 transition flex items-center justify-center">
                <button 
                    onClick={() => handlePlay(song)}
                    className="opacity-0 group-hover:opacity-100 w-12 h-12 bg-orange-500 rounded-full flex items-center justify-center text-white transform translate-y-4 group-hover:translate-y-0 transition duration-300"
                >
                    <FaPlay className="ml-1" />
                </button>
              </div>
            </div>
            <h3 className="font-semibold text-gray-900 truncate">{song.title}</h3>
            <p className="text-sm text-gray-500 truncate">{song.artist}</p>
            
            <div className="flex justify-between items-center mt-2 text-xs text-gray-500">
                <span>▶ {song.plays || 0}</span>
                <button onClick={() => handleLike(song._id)} className="flex items-center hover:text-red-500">
                    <FaHeart className="mr-1" /> {song.likes || 0}
                </button>
            </div>
          </div>
        ))}
      </div>
    </div>
  );
};

export default Home;
